// Worked focus: cmem-canary-rollback-observability — Canary immutable artifacts against memory, crash, latency, allocator, and correctness signals with a tested rollback trigger.
/* Evidence: cmem-worked-cmem-testing-release-incident-defense-2 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 9966; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_testing_release_incident_defense_2(int tests, int sanitizers, int fuzz, int abi, int rollback) {
  int evidence = tests + sanitizers + fuzz + abi + rollback;
  if (!tests || !sanitizers || !fuzz || !abi || !rollback) return 0;
  return evidence + 4;
}

int main(void) {
  int incomplete = worked_cmem_testing_release_incident_defense_2(1, 1, 1, 1, 0);
  int ready = worked_cmem_testing_release_incident_defense_2(1, 1, 1, 1, 1);
  int invariant = incomplete == 0 && ready == 9;
  printf("release evidence=%d invariant=%d\n", ready, invariant);
  return invariant ? 0 : 1;
}

